#!/usr/bin/env python3
# -*- coding: utf-8 -*-
'''
Final Jan local-AI stack applicator v5 (clean-base, robust nested applicators).

Run from a clean, current upstream janhq/jan checkout. This single script applies
all selected feature ports and then runs an integration pass so the features work
together instead of fighting like raccoons in a server rack.
'''
from __future__ import annotations

import base64
import re
import runpy
import shutil
import sys
import time
from pathlib import Path

ROOT = Path.cwd()
TMP = ROOT / '.jan-final-local-ai-stack-tmp'
BASE_APPLICATOR_B64 = ''

REQUIRED_ROOT_MARKERS = [
    'package.json',
    'src-tauri/Cargo.toml',
    'extensions/llamacpp-extension/src/index.ts',
    'extensions/llamacpp-extension/src/preset.ts',
    'extensions/rag-extension/src/index.ts',
    'src-tauri/src/core/server/proxy.rs',
    'web-app/src/routes/hub/index.tsx',
]

FINAL_CHECKS = [
    ('rerank endpoints', 'src-tauri/src/core/server/proxy.rs', ['rerank', 'reranking']),
    ('rerank TS helper', 'extensions/llamacpp-extension/src/rerank.ts', ['normalizeRerankRequest']),
    ('RAG reranking settings', 'extensions/rag-extension/settings.json', ['reranking_mode', 'rerank_candidate_multiplier']),
    ('local embedding selector', 'extensions/llamacpp-extension/settings.json', ['embedding_model_id']),
    ('turboquant cache override', 'extensions/llamacpp-extension/src/preset.ts', ['turbo3', 'turboquant-plus']),
    ('speculative decoding preset', 'extensions/llamacpp-extension/src/preset.ts', ['speculative.type', 'model-draft']),
    ('hub scoring Rust command', 'src-tauri/plugins/tauri-plugin-llamacpp/src/lib.rs', ['score_hub_model']),
    ('llmfit dependency', 'src-tauri/plugins/tauri-plugin-llamacpp/Cargo.toml', ['llmfit-core']),
    ('model score store', 'web-app/src/hooks/useModelScores.ts', ['useModelScore']),
    ('hub category/scoring UI', 'web-app/src/routes/hub/index.tsx', ['category', 'ModelScoreBadge']),
    ('full thread search index', 'web-app/src/lib/search-index.ts', ['ThreadSearchIndex']),
    ('inline code copy', 'web-app/src/containers/RenderMarkdown.tsx', ['copy']),
    ('Windows Makefile Copy-Item', 'Makefile', ['Copy-Item']),
]


def fail(message: str) -> None:
    raise SystemExit(message)


def rel(path: str) -> Path:
    return ROOT / path


def read(path: str) -> str:
    return rel(path).read_text(encoding='utf-8')


def write(path: str, data: str) -> None:
    p = rel(path)
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(data, encoding='utf-8')


def exists(path: str) -> bool:
    return rel(path).exists()


def insert_after(path: str, anchor: str, insertion: str, label: str, marker: str | None = None) -> bool:
    s = read(path)
    if (marker and marker in s) or insertion.strip()[:120] in s:
        return False
    idx = s.find(anchor)
    if idx < 0:
        print(f'[warn] skipped {label} in {path}: anchor not found')
        return False
    idx += len(anchor)
    write(path, s[:idx] + insertion + s[idx:])
    print(f'[ok] {label}')
    return True


def preflight() -> None:
    missing = [p for p in REQUIRED_ROOT_MARKERS if not exists(p)]
    if missing:
        fail('Run this from a clean Jan repository root. Missing:\n  - ' + '\n  - '.join(missing))
    print('[ok] detected Jan repository root')
    patched_markers = [
        ('extensions/llamacpp-extension/src/rerank.ts', 'rerank helper already exists'),
        ('web-app/src/lib/search-index.ts', 'full-text search index already exists'),
        ('web-app/src/hooks/useModelScores.ts', 'model scoring store already exists'),
    ]
    already = [msg for path, msg in patched_markers if exists(path)]
    if already:
        print('[warn] this tree already contains some final-patch files:')
        for msg in already:
            print('       - ' + msg)
        print('       continuing idempotently, but a clean upstream checkout is still the intended target')


def run_embedded_base_applicator() -> None:
    if TMP.exists():
        shutil.rmtree(TMP)
    TMP.mkdir(parents=True, exist_ok=True)
    embedded = TMP / 'apply-jan-rerank-turboquant-features-scoring-full.py'
    embedded.write_bytes(base64.b64decode(BASE_APPLICATOR_B64))
    print(f'>>> running embedded feature applicator: {embedded.relative_to(ROOT)}')
    old_argv = sys.argv[:]
    try:
        sys.argv = [str(embedded)]
        runpy.run_path(str(embedded), run_name='__main__')
    finally:
        sys.argv = old_argv


def write_model_capabilities_helper() -> None:
    path = 'web-app/src/lib/modelCapabilities.ts'
    helper = '''import type { modelInfo } from '@janhq/core'

type MaybeSetting = { controller_props?: { value?: unknown }; controllerProps?: { value?: unknown }; value?: unknown }
type MaybeModel = Partial<modelInfo> & { settings?: Record<string, MaybeSetting>; capabilities?: Record<string, boolean> | string[]; embedding?: boolean; reranking?: boolean }

function settingValue(model: MaybeModel, key: string): unknown {
  const setting = model.settings?.[key]
  return setting?.controller_props?.value ?? setting?.controllerProps?.value ?? setting?.value
}

function capability(model: MaybeModel, key: string): boolean {
  const caps = model.capabilities
  if (Array.isArray(caps)) return caps.includes(key)
  if (caps && typeof caps === 'object') return caps[key] === true
  return false
}

export function isEmbeddingModel(model: MaybeModel): boolean {
  return model.embedding === true || settingValue(model, 'embedding') === true || capability(model, 'embedding')
}

export function isRerankingModel(model: MaybeModel): boolean {
  return model.reranking === true || settingValue(model, 'reranking') === true || capability(model, 'rerank')
}

export function isUtilityOnlyModel(model: MaybeModel): boolean {
  return isEmbeddingModel(model) || isRerankingModel(model)
}

export function isChatCapableModel(model: MaybeModel): boolean {
  return !isUtilityOnlyModel(model) && capability(model, 'chat') !== false
}
'''
    write(path, helper)
    print('[ok] shared model capability helper')


def patch_embedding_resolver_excludes_rerankers() -> None:
    path = 'extensions/llamacpp-extension/src/util.ts'
    if not exists(path):
        return
    s = read(path)
    s = s.replace(
        "models: Array<{ id: string; embedding?: boolean }>",
        "models: Array<{ id: string; embedding?: boolean; reranking?: boolean; capabilities?: { rerank?: boolean; embedding?: boolean } }>",
    )
    s = s.replace(
        "const embeddingModels = models.filter((m) => m.embedding === true).sort((a, b) => a.id.localeCompare(b.id))",
        "const embeddingModels = models\n    .filter((m) => m.embedding === true && m.reranking !== true && m.capabilities?.rerank !== true)\n    .sort((a, b) => a.id.localeCompare(b.id))",
    )
    write(path, s)
    print('[ok] embedding auto-selector excludes reranker-only models')


def patch_model_setting_draft_candidates() -> None:
    path = 'web-app/src/containers/ModelSetting.tsx'
    if not exists(path):
        return
    insert_after(path, "import { useAppState } from '@/hooks/useAppState'\n", "import { isUtilityOnlyModel } from '@/lib/modelCapabilities'\n", 'ModelSetting model capability import', 'isUtilityOnlyModel')
    s = read(path)
    s2 = re.sub(
        r"\.filter\(\s*\(?candidate\)?\s*=>\s*candidate\.id !== model\.id\s*&&\s*!candidate\.settings\?\.embedding\?\.controller_props\?\.value\s*\)",
        ".filter((candidate) => candidate.id !== model.id && !isUtilityOnlyModel(candidate))",
        s,
        count=1,
        flags=re.S,
    )
    if s2 != s:
        write(path, s2)
        print('[ok] draft model dropdown excludes embedding and reranking utility models')
    else:
        print('[warn] draft model dropdown filter anchor not found; check ModelSetting.tsx manually')


def patch_preset_speculative_chat_only() -> None:
    path = 'extensions/llamacpp-extension/src/preset.ts'
    if not exists(path):
        return
    s = read(path)
    if 'const isUtilityModelForRuntime' not in s:
        pattern = (
            r"    const specType = typeof mc\.spec_type === 'string' \? mc\.spec_type\.trim\(\) : ''\n"
            r"    if \(specType && specType !== 'none'\) \{\n"
            r"      lines\.push\(`speculative\.type = \$\{escapeIniValue\(specType\)\}`\)\n"
            r"    \}\n"
            r"    const draftPath = typeof mc\.draft_model_path === 'string' \? mc\.draft_model_path\.trim\(\) : ''\n"
            r"    if \(draftPath\) \{\n"
            r"      lines\.push\(`model-draft = \$\{escapeIniValue\(draftPath\)\}`\)\n"
            r"    \}\n"
            r"    const draftMax = typeof mc\.draft_max === 'number' \? mc\.draft_max : Number\(mc\.draft_max \?\? 0\)\n"
            r"    if \(Number\.isFinite\(draftMax\) && draftMax > 0\) lines\.push\(`draft-max = \$\{Math\.floor\(draftMax\)\}`\)\n"
            r"    const draftMin = typeof mc\.draft_min === 'number' \? mc\.draft_min : Number\(mc\.draft_min \?\? 0\)\n"
            r"    if \(Number\.isFinite\(draftMin\) && draftMin > 0\) lines\.push\(`draft-min = \$\{Math\.floor\(draftMin\)\}`\)\n\n"
        )
        repl = '''    const isUtilityModelForRuntime = mc.embedding === true || mc.reranking === true || mc.capabilities?.embedding === true || mc.capabilities?.rerank === true
    if (!isUtilityModelForRuntime) {
      const specType = typeof mc.spec_type === 'string' ? mc.spec_type.trim() : ''
      if (specType && specType !== 'none') {
        lines.push(`speculative.type = ${escapeIniValue(specType)}`)
      }
      const draftPath = typeof mc.draft_model_path === 'string' ? mc.draft_model_path.trim() : ''
      if (draftPath) {
        lines.push(`model-draft = ${escapeIniValue(draftPath)}`)
      }
      const draftMax = typeof mc.draft_max === 'number' ? mc.draft_max : Number(mc.draft_max ?? 0)
      if (Number.isFinite(draftMax) && draftMax > 0) lines.push(`draft-max = ${Math.floor(draftMax)}`)
      const draftMin = typeof mc.draft_min === 'number' ? mc.draft_min : Number(mc.draft_min ?? 0)
      if (Number.isFinite(draftMin) && draftMin > 0) lines.push(`draft-min = ${Math.floor(draftMin)}`)
    }

'''
        s2, n = re.subn(pattern, lambda _m: repl, s, count=1, flags=re.S)
        if n:
            write(path, s2)
            print('[ok] speculative decoding is limited to chat-capable models in preset generation')
        else:
            print('[warn] speculative preset block anchor not found; check preset.ts manually')
    if 'turboquant-plus' in read(path):
        print('[ok] turboquant-plus preset override present')


def patch_hub_score_prefetch_uses_visible_indices() -> None:
    path = 'web-app/src/routes/hub/index.tsx'
    if not exists(path):
        return
    s = read(path)
    if 'const visibleScoreIndices' not in s and 'rowVirtualizer.getVirtualItems().forEach' in s:
        s = s.replace(
            "  useEffect(() => {\n    rowVirtualizer.getVirtualItems().forEach((virtualItem) => {",
            "  const visibleScoreIndices = rowVirtualizer.getVirtualItems().map((item) => item.index).join(',')\n\n  useEffect(() => {\n    rowVirtualizer.getVirtualItems().forEach((virtualItem) => {",
            1,
        )
        s = s.replace(
            "  }, [fetchModelScore, filteredModels, modelScores])",
            "  }, [fetchModelScore, filteredModels, modelScores, visibleScoreIndices])",
            1,
        )
        write(path, s)
        print('[ok] hub scoring prefetch depends on visible row set instead of every scroll array identity')


def patch_rerank_route_does_not_receive_chat_capabilities() -> None:
    path = 'extensions/llamacpp-extension/src/rerank.ts'
    if exists(path):
        s = read(path)
        if 'Capability toggles are intentionally chat-only' not in s:
            write(path, "// Capability toggles are intentionally chat-only; rerank requests normalize only rerank fields.\n" + s)
            print('[ok] rerank helper marked as isolated from chat capability toggles')



def force_rag_rerank_settings() -> None:
    path = 'extensions/rag-extension/settings.json'
    if not exists(path):
        print('[warn] cannot enforce RAG rerank settings: settings.json missing')
        return
    import json
    try:
        data = json.loads(read(path))
    except Exception as e:
        print(f'[warn] cannot parse {path} to enforce RAG rerank settings: {e}')
        return
    if not isinstance(data, list):
        print(f'[warn] cannot enforce RAG rerank settings: {path} is not a settings array')
        return
    keys = {item.get('key') for item in data if isinstance(item, dict)}
    changed = False
    def add_setting(setting: dict, after_key: str | None = None) -> None:
        nonlocal changed
        if setting['key'] in keys:
            return
        insert_at = len(data)
        if after_key:
            for i, item in enumerate(data):
                if isinstance(item, dict) and item.get('key') == after_key:
                    insert_at = i + 1
                    break
        data.insert(insert_at, setting)
        keys.add(setting['key'])
        changed = True
    add_setting({
        'key': 'reranking_mode',
        'title': 'RAG reranking',
        'description': 'Controls whether document retrieval reranks vector-search candidates with a local reranker model. Auto uses a reranker when available, Off disables reranking, Required fails retrieval when no reranker is available.',
        'controllerType': 'dropdown',
        'controllerProps': {
            'value': 'auto',
            'options': [
                {'value': 'auto', 'name': 'Auto'},
                {'value': 'off', 'name': 'Off'},
                {'value': 'required', 'name': 'Required'},
            ],
        },
    })
    add_setting({
        'key': 'rerank_candidate_multiplier',
        'title': 'Rerank candidate multiplier',
        'description': 'How many first-stage vector candidates to retrieve before reranking. Example: top_k 5 and multiplier 5 retrieves 25 candidates before reranking back to 5.',
        'controllerType': 'input',
        'controllerProps': {'value': 5, 'type': 'number', 'min': 1, 'max': 20, 'step': 1, 'textAlign': 'right'},
    }, 'reranking_mode')
    add_setting({
        'key': 'rerank_max_candidates',
        'title': 'Max rerank candidates',
        'description': 'Hard cap for candidates sent to the reranker. Keeps large document searches from becoming a GPU stress ritual.',
        'controllerType': 'input',
        'controllerProps': {'value': 40, 'type': 'number', 'min': 1, 'max': 100, 'step': 1, 'textAlign': 'right'},
    }, 'rerank_candidate_multiplier')
    if changed:
        write(path, json.dumps(data, indent=2, ensure_ascii=False) + '\n')
        print('[ok] enforced RAG reranking settings including rerank_candidate_multiplier')
    else:
        print('[ok] RAG reranking settings already complete')


def force_turboquant_preset_override() -> None:
    path = 'extensions/llamacpp-extension/src/preset.ts'
    if not exists(path):
        print('[warn] cannot enforce turboquant override: preset.ts missing')
        return
    s = read(path)
    changed = False
    if 'isTurboquantPlusBackend' not in s:
        helper = """
function isTurboquantPlusBackend(versionBackend: unknown): boolean {
  return typeof versionBackend === 'string' && versionBackend.startsWith('turboquant-plus-')
}

"""
        m = re.search(r"function escapeIniValue[\s\S]*?\n}\n\n", s)
        if m:
            s = s[:m.end()] + helper + s[m.end():]
        else:
            m2 = re.search(r"export\s+function\s+|function\s+build", s)
            if m2:
                s = s[:m2.start()] + helper + s[m2.start():]
            else:
                s = helper + s
        changed = True
    if 'cache-type-k = turbo3' not in s or 'cache-type-v = turbo3' not in s:
        block = """
    if (isTurboquantPlusBackend(globalConfig?.version_backend ?? mc.version_backend)) {
      lines.push('cache-type-k = turbo3')
      lines.push('cache-type-v = turbo3')
    }
"""
        cache_re = re.compile(r"(\n\s*if \([^\n]*cache[^\n]*\) \{[\s\S]*?cache-type-v[\s\S]*?\n\s*}\n)", re.I)
        m = cache_re.search(s)
        if m:
            s = s[:m.end()] + block + s[m.end():]
        else:
            marker = "    if (!isUtilityModelForRuntime) {"
            idx = s.find(marker)
            if idx >= 0:
                s = s[:idx] + block + s[idx:]
            else:
                m2 = re.search(r"\n\s*(models|presetModels)\.push\(", s)
                if m2:
                    s = s[:m2.start()] + block + s[m2.start():]
                else:
                    print('[warn] could not find robust insertion point for turboquant cache override in preset.ts')
                    write(path, s)
                    return
        changed = True
    if changed:
        write(path, s)
        print('[ok] enforced turboquant-plus cache-type-k/v turbo3 override')
    else:
        print('[ok] turboquant-plus cache override already complete')

def create_manifest() -> None:
    manifest = ROOT / '.jan-final-local-ai-stack-manifest.txt'
    lines = [
        'Jan final local AI stack patch applied at ' + time.strftime('%Y-%m-%d %H:%M:%S'),
        '',
        'This script targets a clean upstream janhq/jan checkout and applies all local feature ports in one pass.',
        'Run validation:',
        '  pnpm typecheck',
        '  cargo check --manifest-path src-tauri/Cargo.toml',
        '',
        'Feature groups:',
        '  - reranking API and RAG reranking',
        '  - local embedding model selection',
        '  - turboquant-plus backend/cache handling',
        '  - speculative decoding settings/preset support',
        '  - full Hub llmfit scoring',
        '  - Hub categories and model UX changes',
        '  - capability toggles and model lifecycle API',
        '  - copyable inline code',
        '  - full-text thread search',
        '  - Windows Makefile Copy-Item fix',
    ]
    manifest.write_text('\n'.join(lines) + '\n', encoding='utf-8')
    print('[ok] wrote .jan-final-local-ai-stack-manifest.txt')


def run_integration_pass() -> None:
    print('>>> running final integration conflict-resolution pass')
    write_model_capabilities_helper()
    patch_embedding_resolver_excludes_rerankers()
    patch_model_setting_draft_candidates()
    patch_preset_speculative_chat_only()
    force_rag_rerank_settings()
    force_turboquant_preset_override()
    patch_hub_score_prefetch_uses_visible_indices()
    patch_rerank_route_does_not_receive_chat_capabilities()
    create_manifest()


def final_checklist() -> None:
    print('\nFinal self-check:')
    failures: list[str] = []
    for label, path, markers in FINAL_CHECKS:
        if not exists(path):
            failures.append(f'{label}: missing {path}')
            print(f'[missing] {label} -> {path}')
            continue
        s = read(path)
        missing = [m for m in markers if m not in s]
        if missing:
            failures.append(f'{label}: missing markers {missing} in {path}')
            print(f'[warn] {label} missing {missing} in {path}')
        else:
            print(f'[ok] {label}')
    print('\nValidation commands:')
    print('  pnpm typecheck')
    print('  cargo check --manifest-path src-tauri/Cargo.toml')
    print('  git diff --stat')
    if failures:
        print('\nSome self-check markers were not found. The patcher completed, but inspect the warnings above before trusting the build. Because naturally the codebase still gets a vote.')


def main() -> None:
    preflight()
    run_embedded_base_applicator()
    run_integration_pass()
    final_checklist()
    print('\nFinal Jan local-AI stack patch applied. Now let TypeScript and Rust file their inevitable complaints.')


if __name__ == '__main__':
    main()
